function qs() {"use strict";
 var query, parms, i, pos, key, val, qsp;
 qsp = {};
 query = location.search.substring(1);
 parms = query.split('&');
 for (i=parms.length-1; i>=0; i--) {
	pos = parms[i].indexOf('=');
	if (pos > 0) {
	   key = parms[i].substring(0,pos);
	   val = parms[i].substring(pos+1);
	   qsp[key] = val;
	   }
	}
 return qsp;
}

