// Format an address
// @param address inline address with comma delimiter
// @param operator optional separator string for output. Defaults to new line
function reformatAddress(address, separator) {
    separator = separator ? separator : "\n";

    if (!address || address === "")
        return "No address specified";

    let lines = address
        .split(",")
        .map(function (line) { return line.trim() })

    // Remove duplicate lines
    let i = 1;
    while (i < lines.length) {
        if (lines[i] === lines[i - 1]) {
            lines.splice(i, 1);
        } else {
            ++i;
        }
    }

    // Combine first 2 lines if first line is short (e.g. it's a house number)
    if (lines.length > 1 && lines[0].length < 6) {
        lines.splice(0, 2, lines[0] + " " + lines[1]);
    }

    return lines.join(separator);
}

// Format address on 1 line separated by commas
// Each parameter is the name of a form field to be joined into the address
// Pass as many parameters as are required.
// Empty fields will be ignored
// e.g.
//  joinAddressFields(
//        "nonfife_addressline1",
//        "nonfife_addressline2",
//        "nonfife_addressline3",
//        "nonfife_town",
//        "nonfife_postcode",
//        "nonfife_country");
//
function joinAddressFields() {
    let lines = [];
    for (i = 0; i < arguments.length; ++i) {
        let line = KDF.getVal(arguments[i]);
        if (line && line !== "") {
            lines.push(line);
        }
    }
    return lines.join(", ");
}

