    $("#dform_widget_search_" + name + "_search").on("click", ".dform_widget_search_closeresults", function (evt) {
        KDF.hideWidget("bset_" + name + "_search_continue");
    });

    // Property search Back button action. Use javascript to avoid validation ("Move to" button triggers validation when moving forwards.)
    $("#dform_widget_button_but_" + name + "_search_back").off("click").click(function (evt) {
        KDF.gotoPage("page_" + name + '_confirm_address', false, true, true);
    });

    // Manual address input Back button action. Use javascript to avoid validation ("Move to" button triggers validation when moving forwards.)
    $("#dform_widget_button_but_" + name + "_input_back").off("click").click(function (evt) {
        KDF.gotoPage("page_" + name + "_search", false, true, true);
        KDF.hidePage("page_" + name + "_input");
    });

    // Manual address input Continue button
    $("#dform_widget_button_but_" + name + "_input_continue").off("click").click(function (evt) {
        // validate page
        let errors = KDF.check("#dform_page_page_" + name + "_input");
        if (errors === 0) {
            KDF.setVal(name + "_uprn", "");
            let address = joinAddressFields(name + "_addressline1", name + "_addressline2", name + "_addressline3", name + "_town", name + "_postcode", name + "_country");
            KDF.setVal(name + "_address", address);
            KDF.setVal(name + "_formatted_address", reformatAddress(address));
            KDF.gotoPage("page_" + name + "_confirm_address", false, true, true);
            KDF.hidePage("page_" + name + "_input");
        }
    });

    // Make search required e.g. if address not loaded from profile
    propertySearchRequire(name, name + "_address");

    // Stuff for new forms, not when viewing
    if (KDF.kdf().ref === "") {
        // Format address with newlines
        KDF.setVal(name + "_formatted_address", reformatAddress(KDF.getVal(name + "_address")));

        // Associate property to case if we have a UPRN from profile.
        if ($("#dform_widget_" + name + "_search_id").data('setid')) {
            propertySearchAssociateProperty(name);
        }
    }
}

