function getAgeFromDoB(dobString) {
    // expects string in format "yyyy-MM-dd"
    // processing dobString as parsing directly with constructor is discouraged. 
    let dobParts = dobString.split("-").map(Number);
    let dob = new Date(dobParts[0], dobParts[1] - 1, dobParts[2]);    // Month is 0-indexed

    let today = new Date();

    let age = today.getFullYear() - dob.getFullYear();
    if (today.getMonth() < dob.getMonth()
        || (today.getMonth() == dob.getMonth() && today.getDate() < dob.getDate())
    ) {
        age--;
    }
    return age;
}
