/*
  Suggest values to the user as they type
  Values are taken from the named select list
  Field only accepts a value from the list
     inpname : vof field name of input field
     listname: vof field name of select list file
*/
function vof_autosearch(inpname, listname) {
    let inp = $("input[name='" + inpname + "']");
    let listItems = $("div[data-name='" + listname + "'] li").map(function () {
        return $(this).text();
    });
    let container = inp.parent();

    container.addClass("autosearch-container");

    var currentFocus;

    // Event when input is received
    inp.on("input", function (e) {
        var a, b, i, val = this.value;

        closeAllLists();
        if (!val) {
            return false;
        }
        currentFocus = -1;
        // create DIV element to contain the results (values) and append to search field's container
        a = $("<div>");
        a.prop("id", this.id + "autosearch-list");
        a.addClass("autosearch-items");
        container.append(a);

        // For each list item
        for (i = 0; i < listItems.length; i++) {
            let itemVal = listItems[i];
            // check if the item starts with the search string
            if (itemVal.substr(0, val.length).toUpperCase() == val.toUpperCase()) {
                // create a DIV element for the matched result
                b = $("<div>");
                b.html(
                    "<strong>" + itemVal.substr(0, val.length) + "</strong>"
                    + itemVal.substr(val.length)
                );
                b.attr("data-value", itemVal);
                // Event when a result is clicked
                b.on("click", function (e) {
                    inp.val($(this).attr("data-value"));
                    inp.focus();
                    closeAllLists();
                });
                a.append(b);
            }
        }
    });

    // When leaving the field, clear it if current value matches nothing
    inp.on("blur", function () {
        let isMatched = false;
        // For each list item
        for (i = 0; i < listItems.length; i++) {
            let itemVal = listItems[i];
            // check if the item starts with the search string
            if (itemVal.toUpperCase() === this.value.toUpperCase()) {
                this.value = itemVal;
                isMatched = true;
                break;
            }
        }

        if (!isMatched) {
            this.value = "";
        }
    });

    // Keyboard events
    inp.on("keydown", function (e) {
        var x = document.getElementById(this.id + "autosearch-list");
        if (x) x = x.getElementsByTagName("div");
        if (e.keyCode == 40) {
            // DOWN arrow key
            currentFocus++;
            addActive(x);
        } else if (e.keyCode == 38) { //up
            // UP arrow key
            currentFocus--;
            addActive(x);
        } else if (e.keyCode == 13) {
            // ENTER key
            e.preventDefault();
            if (currentFocus > -1) {
                if (x) x[currentFocus].click();
            }
        }
    });

    var addActive = function (x) {
        // classify an item as "active"
        if (!x) return false;
        // Removing the "active" class on all items
        removeActive(x);
        if (currentFocus >= x.length) currentFocus = 0;
        if (currentFocus < 0) currentFocus = (x.length - 1);
        // actvive class to current focus
        x[currentFocus].classList.add("autosearch-active");
    }

    var removeActive = function (x) {
        // Remove the "active" class from all autocomplete items
        for (var i = 0; i < x.length; i++) {
            x[i].classList.remove("autosearch-active");
        }
    }

    var closeAllLists = function (elmnt) {
        //close all autocomplete lists in the document, except the one passed as an argument:
        var x = document.getElementsByClassName("autosearch-items");
        for (var i = 0; i < x.length; i++) {
            if (elmnt != x[i] && elmnt != inp) {
                x[i].parentNode.removeChild(x[i]);
            }
        }
    }

    if (!this.docEventAdded) {
        this.docEventAdded = true;
        document.addEventListener("click", function (e) {
            closeAllLists(e.target);
        });
    }
}

