function convertBNGToLonLat(easting, northing) {
    // Define details British National Grid (BNG) projection mapping
    // Required for converting between projection systems. 
    // further details of useage: http://proj4js.org/
    proj4.defs("EPSG:27700", "+proj=tmerc +lat_0=49 +lon_0=-2 +k=0.9996012717 +x_0=400000 +y_0=-100000 +ellps=airy +datum=OSGB36 +units=m +no_defs");

    return proj4(proj4("EPSG:27700"), proj4("EPSG:4326"), [easting, northing]);
}

function convertLonLatToBNG(longitude, latitude) {
    // Define details British National Grid (BNG) projection mapping
    // Required for converting between projection systems. 
    // further details of useage: http://proj4js.org/
    proj4.defs("EPSG:27700", "+proj=tmerc +lat_0=49 +lon_0=-2 +k=0.9996012717 +x_0=400000 +y_0=-100000 +ellps=airy +datum=OSGB36 +units=m +no_defs");

    return proj4(proj4("EPSG:4326"), proj4("EPSG:27700"), [longitude, latitude]);
}
