/**
 * @fileoverview Standalone JavaScript for Fife Council Header/Footer cutups
 * @description Essential functionality for header and footer components:
 *              - Services drawer with focus management and accessibility
 *              - Mobile search integration with drawer system
 *              - Keyboard navigation and screen reader support
 *              - Focus trapping and ARIA state management
 * @author Fife Council Development Team
 * @version 1.0.0 (Cutup version)
 */

// =============================================================================
// MAIN INITIALIZATION
// =============================================================================

/**
 * Main initialization function - runs when DOM is ready
 * @description Sets up all required functionality for the header/footer
 */
document.addEventListener('DOMContentLoaded', () => {
  // Initialize custom Fife components
  initFifeComponents();
});

// =============================================================================
// FIFE COMPONENTS INITIALIZATION
// =============================================================================

/**
 * Initialize all custom Fife Council components
 * @description Sets up all custom functionality specific to Fife Council
 */
function initFifeComponents() {
  initServicesDrawer();
  initMobileSearch();
}

// =============================================================================
// SERVICES DRAWER FUNCTIONALITY
// =============================================================================

/**
 * Initialize the Services Drawer component
 * @description Handles opening/closing of the services drawer with proper accessibility
 */
function initServicesDrawer() {
  const drawerInstances = document.querySelectorAll('[id$="-services-drawer"]');

  if (drawerInstances.length === 0) return;

  drawerInstances.forEach((drawer) => {
    const drawerId = drawer.id;
    const baseId = drawerId.replace('-services-drawer', '');
    const menuButton = document.getElementById(baseId + '-menu-button');
    const closeButton = document.getElementById(baseId + '-close-button');

    // Ensure drawer is hidden by default
    drawer.setAttribute('aria-hidden', 'true');

    // Initialize this drawer instance
    if (menuButton) {
      initSingleDrawer(menuButton, closeButton, drawer);
    }
  });
}

/**
 * Initialize a single drawer instance
 * @param {HTMLElement} menuButton - The menu button element
 * @param {HTMLElement} closeButton - The close button element (may be null)
 * @param {HTMLElement} drawer - The drawer element
 */
function initSingleDrawer(menuButton, closeButton, drawer) {

  // =============================================================================
  // EVENT LISTENERS
  // =============================================================================

  /**
   * Toggle drawer functionality
   * @description Toggles drawer state based on current aria-expanded value
   */
  menuButton.addEventListener('click', (e) => {
    e.preventDefault();
    const isExpanded = menuButton.getAttribute('aria-expanded') === 'true';

    if (isExpanded) {
      closeDrawer();
    } else {
      openDrawer();
    }
  });

  /**
   * Close drawer functionality via close button
   * @description Closes the drawer and restores focus to menu button
   */
  if (closeButton) {
    closeButton.addEventListener('click', (e) => {
      e.preventDefault();
      closeDrawer();
    });
  }

  /**
   * Keyboard support - Escape key closes drawer
   * @description Allows users to close drawer using Escape key
   */
  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape' && drawer.getAttribute('aria-hidden') === 'false') {
      closeDrawer();
    }
  });

  /**
   * Backdrop click to close
   * @description Closes drawer when clicking outside the content area
   */
  drawer.addEventListener('click', (e) => {
    if (e.target === drawer) {
      closeDrawer();
    }
  });

  // =============================================================================
  // DRAWER FUNCTIONS
  // =============================================================================

  /**
   * Opens the services drawer
   * @description Sets drawer to visible, manages focus, and updates ARIA attributes
   */
  function openDrawer() {
    drawer.setAttribute('aria-hidden', 'false');
    menuButton.setAttribute('aria-expanded', 'true');
    menuButton.setAttribute('aria-label', 'Close menu');

    // Update visual state via CSS classes and SVG icon
    menuButton.classList.remove('fife-header__nav-button--menu');
    menuButton.classList.add('fife-header__nav-button--close');

    // Update SVG icon to close (X)
    const svg = menuButton.querySelector('svg');
    if (svg) {
      svg.innerHTML = '<path d="M6 6L18 18M6 18L18 6" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>';
    }

    const firstLink = drawer.querySelector('.fife-services-drawer__link');
    if (firstLink) {
      firstLink.focus();
    }
    trapFocus(drawer);
  }

  /**
   * Closes the services drawer
   * @description Hides drawer, restores focus to menu button, and updates ARIA attributes
   */
  function closeDrawer() {
    drawer.setAttribute('aria-hidden', 'true');
    menuButton.setAttribute('aria-expanded', 'false');
    menuButton.setAttribute('aria-label', 'Open menu');

    // Update visual state via CSS classes and SVG icon
    menuButton.classList.remove('fife-header__nav-button--close');
    menuButton.classList.add('fife-header__nav-button--menu');

    // Update SVG icon to hamburger menu
    const svg = menuButton.querySelector('svg');
    if (svg) {
      svg.innerHTML = '<path d="M3 6H21M3 12H21M3 18H21" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>';
    }

    // Restore focus to menu button
    menuButton.focus();
  }

  /**
   * Traps focus within the drawer for keyboard navigation
   * @param {HTMLElement} element - The drawer element to trap focus within
   * @description Prevents focus from leaving the drawer when using Tab key
   */
  function trapFocus(element) {
    const focusableElements = element.querySelectorAll(
      'a[href], button, textarea, input[type="text"], input[type="radio"], input[type="checkbox"], select'
    );

    if (focusableElements.length === 0) return;

    const firstFocusable = focusableElements[0];
    const lastFocusable = focusableElements[focusableElements.length - 1];

    element.addEventListener('keydown', function(e) {
      if (e.key === 'Tab') {
        if (e.shiftKey) {
          if (document.activeElement === firstFocusable) {
            e.preventDefault();
            lastFocusable.focus();
          }
        } else {
          if (document.activeElement === lastFocusable) {
            e.preventDefault();
            firstFocusable.focus();
          }
        }
      }
    });
  }
}

// =============================================================================
// MOBILE SEARCH FUNCTIONALITY
// =============================================================================

/**
 * Initialize mobile search button functionality
 * @description Opens services drawer and focuses on mobile search input
 */
function initMobileSearch() {
  const mobileSearchButtons = document.querySelectorAll('.fife-header__mobile-search');

  mobileSearchButtons.forEach(button => {
    button.addEventListener('click', () => {
      const header = button.closest('.fife-header');
      const drawer = header?.querySelector('.fife-services-drawer');
      const menuButton = header?.querySelector('[id$="-menu-button"]');

      if (!drawer || !menuButton) return;
      drawer.setAttribute('aria-hidden', 'false');
      menuButton.setAttribute('aria-expanded', 'true');

      const searchInput = drawer.querySelector('#fife-mobile-search');
      const fallbackLink = drawer.querySelector('.fife-services-drawer__link');

      if (searchInput) {
        searchInput.focus();
      } else if (fallbackLink) {
        fallbackLink.focus();
      }

      // Apply focus trap for accessibility (reuse existing trapFocus logic)
      setupFocusTrap(drawer);
    });
  });
}

/**
 * Sets up focus trap for drawer (extracted from initSingleDrawer)
 * @param {HTMLElement} drawer - The drawer element
 */
function setupFocusTrap(drawer) {
  const focusableElements = drawer.querySelectorAll(
    'a[href], button, textarea, input[type="text"], input[type="radio"], input[type="checkbox"], select'
  );

  if (focusableElements.length === 0) return;

  const firstFocusable = focusableElements[0];
  const lastFocusable = focusableElements[focusableElements.length - 1];

  const handleTabKey = (e) => {
    if (e.key === 'Tab') {
      if (e.shiftKey) {
        if (document.activeElement === firstFocusable) {
          e.preventDefault();
          lastFocusable.focus();
        }
      } else {
        if (document.activeElement === lastFocusable) {
          e.preventDefault();
          firstFocusable.focus();
        }
      }
    }
  };

  drawer.removeEventListener('keydown', handleTabKey);
  drawer.addEventListener('keydown', handleTabKey);
}

